#include <algorithm>
#include <climits>
using namespace std;
int maxSumOfSubarrayWithKConsecutiveElements(vector<int>& nums, int k) {
 int n = nums.size();
 if (k > n) return 0;
 long long prefixSum[n + 1] = {0};
 for (int i = 1; i <= n; i++)
  prefixSum[i] = prefixSum[i - 1] + nums[i - 1];
 int maxSum = 0;
 for (int start = 0; start < n - k + 1; start++) {
  int currentSum = prefixSum[start + k] - prefixSum[start];
  maxSum = max(maxSum, currentSum);
 }
 return maxSum;
}
